import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.Pywvta2k.js";const x=JSON.parse('{"title":"温病学派","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/04-明清/04-温病学派（叶天士-吴鞠通）.md","filePath":"tcm-data/04-明清/04-温病学派（叶天士-吴鞠通）.md","lastUpdated":1781084559000}'),n={name:"tcm-data/04-明清/04-温病学派（叶天士-吴鞠通）.md"};function d(s,t,o,i,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="温病学派" tabindex="-1">温病学派 <a class="header-anchor" href="#温病学派" aria-label="Permalink to &quot;温病学派&quot;">​</a></h1><blockquote><p>叶天士（1666-1745年），江苏吴县人 吴鞠通（1758-1836年），江苏淮阴人 温病学说的创立者与集大成者 代表作：《温热论》（叶天士）、《温病条辨》（吴鞠通）</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><h3 id="叶天士" tabindex="-1">叶天士 <a class="header-anchor" href="#叶天士" aria-label="Permalink to &quot;叶天士&quot;">​</a></h3><ul><li><strong>字号</strong>：名桂，号香岩</li><li><strong>生平</strong>：祖父、父亲皆为名医。14岁丧父，师从17位老师</li><li><strong>著作</strong>：《温热论》（口述，由弟子顾景文整理）、《临证指南医案》</li><li><strong>学术地位</strong>：<strong>温病学说的奠基人</strong>，卫气营血辨证的创立者</li></ul><h3 id="吴鞠通" tabindex="-1">吴鞠通 <a class="header-anchor" href="#吴鞠通" aria-label="Permalink to &quot;吴鞠通&quot;">​</a></h3><ul><li><strong>字号</strong>：名瑭，字鞠通</li><li><strong>生平</strong>：19岁因父亲病逝而立志学医，钻研叶天士著作</li><li><strong>著作</strong>：《温病条辨》（仿《伤寒论》体例）</li><li><strong>学术地位</strong>：<strong>温病学说的集大成者</strong>，三焦辨证的创立者</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-卫气营血辨证-叶天士" tabindex="-1">1. 卫气营血辨证（叶天士） <a class="header-anchor" href="#_1-卫气营血辨证-叶天士" aria-label="Permalink to &quot;1. 卫气营血辨证（叶天士）&quot;">​</a></h3><blockquote><p><strong>「卫之后方言气，营之后方言血。」</strong><strong>「在卫汗之，到气清气，入营透热转气，入血凉血散血。」</strong></p></blockquote><p>温病的四个层次：</p><table tabindex="0"><thead><tr><th style="text-align:left;">层次</th><th style="text-align:left;">病位</th><th style="text-align:left;">症状</th><th style="text-align:left;">治法</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>卫分</strong></td><td style="text-align:left;">肺、皮毛</td><td style="text-align:left;">发热、微恶寒、咳嗽</td><td style="text-align:left;">辛凉解表</td></tr><tr><td style="text-align:left;"><strong>气分</strong></td><td style="text-align:left;">胃、肠、肺</td><td style="text-align:left;">高热、口渴、大汗</td><td style="text-align:left;">清气泄热</td></tr><tr><td style="text-align:left;"><strong>营分</strong></td><td style="text-align:left;">心包</td><td style="text-align:left;">身热夜甚、心烦、斑疹</td><td style="text-align:left;">清营透热</td></tr><tr><td style="text-align:left;"><strong>血分</strong></td><td style="text-align:left;">心、肝、肾</td><td style="text-align:left;">出血、抽搐、神昏</td><td style="text-align:left;">凉血散血</td></tr></tbody></table><h3 id="_2-三焦辨证-吴鞠通" tabindex="-1">2. 三焦辨证（吴鞠通） <a class="header-anchor" href="#_2-三焦辨证-吴鞠通" aria-label="Permalink to &quot;2. 三焦辨证（吴鞠通）&quot;">​</a></h3><blockquote><p><strong>「治上焦如羽，非轻不举；治中焦如衡，非平不安；治下焦如权，非重不沉。」</strong></p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">三焦</th><th style="text-align:left;">对应脏腑</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>上焦</strong></td><td style="text-align:left;">心肺</td><td style="text-align:left;">病位浅，治宜轻清</td></tr><tr><td style="text-align:left;"><strong>中焦</strong></td><td style="text-align:left;">脾胃</td><td style="text-align:left;">湿热困阻，治宜中和</td></tr><tr><td style="text-align:left;"><strong>下焦</strong></td><td style="text-align:left;">肝肾</td><td style="text-align:left;">病位深，治宜重镇</td></tr></tbody></table><h3 id="_3-伤寒与温病的区别" tabindex="-1">3. 伤寒与温病的区别 <a class="header-anchor" href="#_3-伤寒与温病的区别" aria-label="Permalink to &quot;3. 伤寒与温病的区别&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">伤寒</th><th style="text-align:left;">温病</th></tr></thead><tbody><tr><td style="text-align:left;">病因</td><td style="text-align:left;">寒邪</td><td style="text-align:left;">热邪</td></tr><tr><td style="text-align:left;">传变</td><td style="text-align:left;">六经传变，由表入里</td><td style="text-align:left;">卫气营血/三焦传变</td></tr><tr><td style="text-align:left;">特点</td><td style="text-align:left;">伤阳气</td><td style="text-align:left;">伤阴液</td></tr><tr><td style="text-align:left;">治法</td><td style="text-align:left;">温阳为主</td><td style="text-align:left;">清热养阴为主</td></tr><tr><td style="text-align:left;">代表方</td><td style="text-align:left;">麻黄汤、四逆汤</td><td style="text-align:left;">银翘散、桑菊饮</td></tr></tbody></table><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><h3 id="叶天士贡献" tabindex="-1">叶天士贡献 <a class="header-anchor" href="#叶天士贡献" aria-label="Permalink to &quot;叶天士贡献&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">出处</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>银翘散</strong></td><td style="text-align:left;">《温病条辨》（源于叶案）</td><td style="text-align:left;">风温初起</td></tr><tr><td style="text-align:left;"><strong>桑菊饮</strong></td><td style="text-align:left;">《温病条辨》（源于叶案）</td><td style="text-align:left;">风温咳嗽</td></tr><tr><td style="text-align:left;"><strong>清营汤</strong></td><td style="text-align:left;">《温病条辨》（源于叶案）</td><td style="text-align:left;">热入营分</td></tr></tbody></table><h3 id="吴鞠通原创" tabindex="-1">吴鞠通原创 <a class="header-anchor" href="#吴鞠通原创" aria-label="Permalink to &quot;吴鞠通原创&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>银翘散</strong></td><td style="text-align:left;">银花、连翘、桔梗、薄荷、竹叶、甘草、荆芥、淡豆豉、牛蒡子、芦根</td><td style="text-align:left;">风温初起</td></tr><tr><td style="text-align:left;"><strong>桑菊饮</strong></td><td style="text-align:left;">桑叶、菊花、杏仁、连翘、薄荷、桔梗、甘草、苇根</td><td style="text-align:left;">风温咳嗽</td></tr><tr><td style="text-align:left;"><strong>清营汤</strong></td><td style="text-align:left;">犀角、生地、玄参、竹叶、麦冬、丹参、黄连、银花、连翘</td><td style="text-align:left;">热入营分</td></tr><tr><td style="text-align:left;"><strong>三仁汤</strong></td><td style="text-align:left;">杏仁、白蔻仁、薏苡仁、滑石、通草、竹叶、厚朴、半夏</td><td style="text-align:left;">湿温初起</td></tr><tr><td style="text-align:left;"><strong>安宫牛黄丸</strong></td><td style="text-align:left;">牛黄、郁金、犀角、黄连、朱砂、冰片、麝香、珍珠、金箔</td><td style="text-align:left;">热入心包，神昏</td></tr><tr><td style="text-align:left;"><strong>大定风珠</strong></td><td style="text-align:left;">白芍、阿胶、龟板、生地、麻仁、五味子、牡蛎、麦冬、甘草、鳖甲、鸡子黄</td><td style="text-align:left;">阴虚风动</td></tr></tbody></table><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><h3 id="叶天士-1" tabindex="-1">叶天士 <a class="header-anchor" href="#叶天士-1" aria-label="Permalink to &quot;叶天士&quot;">​</a></h3><blockquote><p><strong>「卫之后方言气，营之后方言血。」</strong><strong>「在卫汗之，到气清气，入营透热转气，入血凉血散血。」</strong><strong>「温邪上受，首先犯肺，逆传心包。」</strong><strong>「救阴不在血，而在津与汗。」</strong></p></blockquote><h3 id="吴鞠通-1" tabindex="-1">吴鞠通 <a class="header-anchor" href="#吴鞠通-1" aria-label="Permalink to &quot;吴鞠通&quot;">​</a></h3><blockquote><p><strong>「治上焦如羽，非轻不举。」</strong><strong>「治中焦如衡，非平不安。」</strong><strong>「治下焦如权，非重不沉。」</strong><strong>「伤寒伤人身之阳，温病伤人身之阴。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><ul><li>银翘散、桑菊饮是现代治疗风热感冒的标准方</li><li>安宫牛黄丸是急救中风的特效药</li><li>温病学说填补了《伤寒论》在温热病方面的空白</li></ul><h3 id="与黄元御的对比" tabindex="-1">与黄元御的对比 <a class="header-anchor" href="#与黄元御的对比" aria-label="Permalink to &quot;与黄元御的对比&quot;">​</a></h3><p>黄元御不承认温病学派——他认为&quot;温病也是伤寒&quot;，本质是少阴水寒导致的相火不降。这是一个重要的学术分歧。在临床上，<strong>急性发热性传染病</strong>适合温病学思路，<strong>慢性虚损性内伤病</strong>适合黄元御思路。</p><hr><p><em>本条目为精简框架版。可扩展至温病与伤寒的临床鉴别、温病代表方剂详解等专题。</em></p>',38)])])}const y=e(n,[["render",d]]);export{x as __pageData,y as default};
